import {BackupConfig} from "./BackupConfig";
import {BackupDestination, SystemEvent} from '../../javaTypes';
import { createRoot } from "react-dom/client";

declare global {
    interface Window {
        isReplica?: boolean,
        replicaPassword?: string,
        backupDestinations: BackupDestination[],
        importStatuses?: SystemEvent[]
    }
}

const container = document.getElementById('backupConfiguration');
if(!container) {
    console.error("Mount point for ref container not found")
} else {
    const root = createRoot(container);
    root.render(<BackupConfig isReplica={window.isReplica || false} replicaPassword={window.replicaPassword || ''} backupDestinations={window.backupDestinations} importStatuses={window.importStatuses}/>);
}
