import {t} from "ftc-common/i18n";
import {promptDialog, messageDialog} from "first-common/dialogs";
import {useState} from "react";
import {BackupDestination, SystemEvent} from "../../javaTypes";

function BackupDestinationDetails({destination, remove}: { destination: BackupDestination, remove: (uri: string) => void }) {
    const url = new URL(destination.uri);
    let text: JSX.Element | string = destination.uri;
    if(url.protocol == 'file:') {
        text = t`Directory: ${url.pathname}`
    } else if(url.protocol.startsWith("http")) {
        url.username = '';
        url.password = '';
        text = <>{t`Remote server: `}<a href={url.href} target="_blank" rel="noreferrer">{url.host}</a></>
    }
    const lastAttempt = destination.lastAttempt ? new Date(destination.lastAttempt).toLocaleString() : 'unknown';
    return <li>{text} {destination.lastError ? <>
        <i className="fa fa-exclamation-triangle"></i>{t`(backup failed at ${lastAttempt})`}
    </> : t`(last backed up at ${lastAttempt})`}<button className={"btn btn-sm btn-danger"} onClick={() => remove(destination.uri)}><i className={"fas fa-trash"}></i></button>
        {destination.lastError ? <details><pre style={{whiteSpace: 'pre-wrap'}}>{destination.lastError}</pre></details> : null}
    </li>
}

function ImportStatus({data}: { data: SystemEvent }) {
    return <li>{data.event}: ({new Date(data.timestamp).toLocaleString()}) </li>;
}

export function BackupConfig({isReplica: origIsReplica, replicaPassword: origReplicaPassword, backupDestinations: origBackupDestinations, importStatuses}: {
    isReplica: boolean,
    replicaPassword: string,
    backupDestinations: BackupDestination[],
    importStatuses?: SystemEvent[]
}) {
    const [isReplica, setIsReplica] = useState(origIsReplica);
    const [replicaPassword, setReplicaPassword] = useState(origReplicaPassword);
    const [backupDestinations, setBackupDestinations] = useState(origBackupDestinations);
    async function setReplica(isReplica: boolean) {
        const params = new URLSearchParams();
        params.append("isReplica", isReplica ? 'true' : 'false');
        const res = await fetch("/manage/togglereplica/", {
            method: 'POST',
            body: params
        })
        const response = await res.json();
        setIsReplica(isReplica);
        if (isReplica) {
            setReplicaPassword(response.replicaPassword);
        }
    }

    async function addRemoteServer() {
        const server = await promptDialog({
            label: t`Add remote server`,
            text: t`Remote address`,
            buttonText: t`Add`
        })
        if(!server) {
            return;
        }
        const password = await promptDialog({
            label: t`Add remote server`,
            text: t`Backup server password`,
            buttonText: t`Add`
        })
        if(!password) {
            return;
        }
        await addBackupDestination(`http://ems:${password}@${server}`)
    }

    async function addDirectory() {
        const dir = await promptDialog({
            label: t`Add directory`,
            text: t`Path to store backups (e.g. D:/ftc-backup or /Volumes/MyDrive/ftc-backup)`,
            buttonText: t`Add`
        })
        if(!dir) {
            return;
        }
        let prefix = '';
        if(dir.match(/^[a-z]:/i)) {
            prefix = '/';
        }
        await addBackupDestination(`file://${prefix}${dir}`)
    }

    async function addBackupDestination(uri: string) {
        const params = new URLSearchParams();
        params.append("uri", uri);
        const res = await fetch("/manage/backup/", {
            method: 'PUT',
            body: params
        })
        const text = await res.text();
        if(text != 'OK') {
            messageDialog({label: t`Add failed`, text: t`Failed to add backup destination`})
        } else {
            setBackupDestinations((was) => [...was, {
                uri,
                lastAttempt: Date.now(),
            } as BackupDestination])
        }
    }

    async function removeBackupDestination(uri: string) {
        const params = new URLSearchParams();
        params.append("uri", uri);
        const res = await fetch(`/manage/backup/`, {
            method: 'DELETE',
            body: params
        })
        const text = await res.text();
        if(text != 'OK') {
            messageDialog({label: t`Add failed`, text: t`Failed to remove backup destination`})
        } else {
            setBackupDestinations((was) => was.filter(bd => bd.uri !== uri))
        }
    }

    return <fieldset>
        <legend>{t`Backup Configuration`}</legend>
        {isReplica ? <>
            <p>{t`Backup last loaded`}</p>
            <ul>
                {importStatuses?.sort((a, b) => a.event.localeCompare(b.event)).map((is) => <ImportStatus key={is.event} data={is} />)}
            </ul>
        </> : <>
            <p>{t`Backup destinations`}</p>
            <ul>
                {backupDestinations.map((bd) => <BackupDestinationDetails key={bd.uri} destination={bd} remove={removeBackupDestination} />)}
            </ul>

            <button className={"btn btn-small btn-secondary"} onClick={addRemoteServer}>{t`Add remote server`}</button>
            <button className={"btn btn-small btn-secondary ml-2"} onClick={addDirectory}>{t`Add directory`}</button>
        </>}

        <p>{isReplica ?
            t`Currently acting as replica. Replication password: ${replicaPassword}` :
            t`Currently acting as primary.`
        }</p>
        <button className={`btn btn-${isReplica ? 'danger' : 'warning'}`} onClick={() => setReplica(!isReplica)}>{isReplica ? t`Become Primary` : t`Become Replica`}</button>
        <br/>
        <small>{isReplica ?
            t`This should only be done if the current primary server is now offline` :
            t`Receive updates from a primary server so this server is ready to take over at a moment's notice`}</small>
    </fieldset>
}